t.script:
//
(function(){
document.addEventListener('DOMContentLoaded', function(){

    var skillData = {};
    try { skillData = JSON.parse(document.getElementById('skillDataContainer').dataset.skillJson || '{}'); }
    catch(e) { skillData = {skills:{}, levels:{}}; }

    var BASE_URL      = '/my/employee/experience';
    var EXP_KEY       = 'ess_exp_staging';
    var csrfToken     = (document.getElementById('exp_csrf_token') || {}).value || '';
    var pendingChanges = [];

    /* ── Restore staged changes from localStorage when page loads ── */
    (function restoreFromStorage() {
        try {
            var stored = JSON.parse(localStorage.getItem(EXP_KEY) || 'null');
            if (!stored || !stored.changes || stored.changes.length === 0) return;
            stored.changes.forEach(function(c) {
                if (c.type === 'add_batch' && c.payload && c.payload.batch_skills) {
                    pendingChanges.push(c);
                    var tbody = document.getElementById('skillTableBody');
                    var emptyRow = document.getElementById('skillEmptyRow');
                    if (emptyRow) emptyRow.remove();
                    c.payload.batch_skills.forEach(function(item) {
                        var rowTempId = --tempId;
                        var tr = document.createElement('tr');
                        tr.setAttribute('data-id', rowTempId);
                        tr.setAttribute('data-skill-name', item.skill_name || '');
                        tr.setAttribute('data-type-name',  item.type_name  || '');
                        tr.setAttribute('data-type-id',    item.type_id    || '');
                        tr.setAttribute('data-level-name', item.level_name || '');
                        tr.setAttribute('data-level-id',   item.level_id   || '');
                        tr.classList.add('skill-staged-add');
                        tr.innerHTML =
                            '<td style="padding:13px 18px;vertical-align:middle;font-size:14px;" class="col-type-name">' + esc(item.type_name) + '</td>' +
                            '<td style="padding:13px 18px;vertical-align:middle;font-size:14px;" class="col-skill-name">' + esc(item.skill_name) + '<span class="skill-badge badge-new">New</span></td>' +
                            '<td style="padding:13px 18px;vertical-align:middle;font-size:14px;" class="col-level-name"><span class="badge bg-primary">' + esc(item.level_name) + '</span></td>' +
                            '<td class="skill-action-col" style="display:none;padding:13px 18px;vertical-align:middle;text-align:right;">' +
                            '<button type="button" class="btn btn-sm btn-outline-danger ess-btn-delete-skill" data-id="' + rowTempId + '"><i class="fa fa-trash"></i></button></td>';
                        if (tbody) { tbody.appendChild(tr); bindDelete(tr); }
                    });
                } else if (c.type === 'edit' && c.rowId) {
                    pendingChanges.push(c);
                    var row = getRow(c.rowId);
                    if (row && c.payload) {
                        row.setAttribute('data-level-id',   c.payload.level_id   || '');
                        row.setAttribute('data-level-name', c.payload.level_name || '');
                        row.querySelector('.col-level-name').innerHTML = '<span class="badge bg-primary">' + esc(c.payload.level_name) + '</span>';
                        row.classList.add('skill-staged-edit');
                        setBadge(row, 'edit');
                    }
                } else if (c.type === 'delete' && c.rowId) {
                    pendingChanges.push(c);
                    var row = getRow(c.rowId);
                    if (row) {
                        row.classList.add('skill-staged-delete');
                        setBadge(row, 'delete');
                        row.querySelector('.skill-action-col').innerHTML =
                            '<button type="button" class="btn btn-sm btn-outline-secondary ess-btn-undo" data-id="' + c.rowId + '"><i class="fa fa-undo me-1"></i>Undo</button>';
                        bindUndo(row);
                    }
                }
            });
            /* If we restored anything, auto-enter edit mode */
            if (pendingChanges.length > 0) {
                enableEdit();
            }
        } catch(e) {}
    })();
    var modalQueue     = [];
    var tempId         = -1;
    var isSubmitting   = false;

    /* ── Fix last-updated timezone ── */
    (function(){
        var el = document.getElementById('expLastUpdated');
        if(!el) return;
        var raw = (el.textContent||'').trim().replace(/\u00a0/g,' ');
        if(!raw || raw === 'Never') return;
        try{
            var m = raw.match(/(\d{1,2})\s+(\w+),?\s+(\d{4})\s+at\s+(\d{1,2}):(\d{2})\s*(AM|PM)/i);
            if(!m) return;
            var mo = {jan:0,feb:1,mar:2,apr:3,may:4,jun:5,jul:6,aug:7,sep:8,oct:9,nov:10,dec:11};
            var hr = parseInt(m[4],10), isPM = m[6].toUpperCase()==='PM';
            if(isPM&&hr<12)hr+=12; if(!isPM&&hr===12)hr=0;
            var dt = new Date(Date.UTC(parseInt(m[3],10), mo[m[2].toLowerCase().substring(0,3)], parseInt(m[1],10), hr, parseInt(m[5],10)));
            if(!isNaN(dt.getTime()))
                el.textContent = dt.toLocaleString(undefined,{day:'2-digit',month:'short',year:'numeric',hour:'2-digit',minute:'2-digit',hour12:true});
        }catch(e){}
    })();

    /* ── Helpers ── */
    function showMsg(text, type) {
        var c  = document.getElementById('expMessageContainer');
        var s  = document.getElementById('expSuccessMessage');
        var er = document.getElementById('expErrorMessage');
        s.style.display='none';  s.classList.remove('show');
        er.style.display='none'; er.classList.remove('show');
        if(type === 'success' || type === 'info'){
            document.getElementById('expSuccessText').textContent = text;
            s.style.display='block'; s.classList.add('show');
        } else {
            document.getElementById('expErrorText').textContent = text;
            er.style.display='block'; er.classList.add('show');
        }
        c.style.display='block';
        c.scrollIntoView({behavior:'smooth'});
        setTimeout(function(){ s.classList.remove('show'); er.classList.remove('show'); }, 6000);
    }

    function esc(str){ return String(str||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }
    function openModal(id)  { document.getElementById(id).style.display='flex'; }
    function closeModal(id) { document.getElementById(id).style.display='none'; }
    function getRow(id)     { return document.querySelector('#skillTableBody tr[data-id="'+id+'"]'); }
    function clearBadge(row){ var b=row.querySelector('.skill-badge'); if(b) b.remove(); }

    function setBadge(row, type){
        clearBadge(row);
        var labels  = {add:'New', edit:'Edited', delete:'To Delete'};
        var classes = {add:'badge-new', edit:'badge-edited', delete:'badge-delete'};
        var s = document.createElement('span');
        s.className = 'skill-badge ' + classes[type];
        s.textContent = labels[type];
        var cell = row.querySelector('.col-skill-name');
        if(cell) cell.appendChild(s);
    }

    function updateBadge(){
        var el = document.getElementById('expPendingBadge');
        var ct = document.getElementById('expPendingCount');
        ct.textContent = pendingChanges.length;
        el.style.display = pendingChanges.length > 0 ? 'block' : 'none';
    }

    /* Save serialisable pending changes to localStorage so the global
       submit bar in base.xml can read and submit them from any tab */
    function saveToStorage() {
        try {
            var toStore = pendingChanges.filter(function(c) {
                return c.type !== 'resume'; /* files cannot go in localStorage */
            }).map(function(c) {
                return { type: c.type, rowId: c.rowId, payload: c.payload };
            });
            if (toStore.length > 0) {
                localStorage.setItem(EXP_KEY, JSON.stringify({ changes: toStore }));
            } else {
                localStorage.removeItem(EXP_KEY);
            }
        } catch(e) {}
    }

    /* ── FIX 1: Lock Edit button if pending HR approval exists ── */
    (function lockIfPending(){
        var hasPendingSkill  = document.getElementById('pendingSkillCard');
        var hasPendingResume = document.querySelector('.alert .fa-clock-o'); /* pending resume banner */
        var editBtn          = document.getElementById('expEditBtn');
        if ((hasPendingSkill || hasPendingResume) && editBtn) {
            editBtn.disabled = true;
            editBtn.innerHTML = '<i class="fa fa-lock me-1"></i>Pending HR Review';
            editBtn.classList.remove('btn-outline-primary');
            editBtn.classList.add('btn-warning');
            editBtn.style.cursor = 'not-allowed';
            editBtn.title = 'Editing locked — a change is pending HR review';
        }
    })();

    /* ── Save before navigating to another portal tab (no browser dialog) ── */
    /* The base template calls essSaveBeforeNav() when a nav tab is clicked */
    window.essSaveBeforeNav = function() {
        saveToStorage();
    };

    window.essHasUnsavedChanges = function() {
        return pendingChanges.length > 0;
    };

    /* beforeunload removed — base template intercepts tab clicks and
       calls essSaveBeforeNav() before navigating, so no dialog appears.
       Only browser close/refresh would lose data, which is acceptable. */

    /* ── Disclaimer gates Save button ── */
    document.getElementById('expDisclaimer').addEventListener('change', function(){
        var btn = document.getElementById('expSaveBtn');
        btn.disabled    = !this.checked;
        btn.style.opacity = this.checked ? '1' : '0.6';
    });

    /* ── Resume file input ── */
    var resumeFileInput = document.getElementById('resumeFileInput');
    if(resumeFileInput){
        resumeFileInput.addEventListener('change', function(){
            var errEl  = document.getElementById('resumeFileError');
            var lblEl  = document.getElementById('resumeFileLabel');
            var nameEl = document.getElementById('resumeFileName');
            errEl.style.display = 'none';
            if(!this.files || this.files.length === 0){
                lblEl.style.display = 'none';
                pendingChanges = pendingChanges.filter(function(c){ return c.type !== 'resume'; });
                updateBadge(); return;
            }
            var file = this.files[0];
            var allowed = ['application/pdf','application/msword','application/vnd.openxmlformats-officedocument.wordprocessingml.document'];
            if(allowed.indexOf(file.type) === -1){
                errEl.textContent = 'Only PDF, DOC, and DOCX files are allowed.';
                errEl.style.display = 'block'; this.value = ''; return;
            }
            if(file.size > 10 * 1024 * 1024){
                errEl.textContent = 'File size must not exceed 10 MB.';
                errEl.style.display = 'block'; this.value = ''; return;
            }
            nameEl.textContent = file.name;
            lblEl.style.display = 'block';
            pendingChanges = pendingChanges.filter(function(c){ return c.type !== 'resume'; });
            pendingChanges.push({ type:'resume', rowId:null, payload:{ filename: file.name } });
            updateBadge();
            showMsg('Resume staged. Accept the disclaimer and click "Submit for HR Approval".', 'info');
        });
    }

    /* ── Cascading dropdowns ── */
    var typeSelect  = document.getElementById('modalSkillType');
    var skillSelect = document.getElementById('modalSkill');
    var levelSelect = document.getElementById('modalLevel');

    typeSelect.addEventListener('change', function(){
        var typeId = this.value;
        skillSelect.innerHTML = '<option value="">— Select Skill —</option>';
        levelSelect.innerHTML = '<option value="">— Select Level —</option>';
        skillSelect.disabled = true; levelSelect.disabled = true;
        if(!typeId) return;
        (skillData.skills[typeId]||[]).forEach(function(sk){
            var opt = document.createElement('option'); opt.value=sk.id; opt.textContent=sk.name; skillSelect.appendChild(opt);
        });
        skillSelect.disabled = (skillData.skills[typeId]||[]).length === 0;
        (skillData.levels[typeId]||[]).forEach(function(lv){
            var opt = document.createElement('option'); opt.value=lv.id; opt.textContent=lv.name; levelSelect.appendChild(opt);
        });
        levelSelect.disabled = (skillData.levels[typeId]||[]).length === 0;
    });

    /* ── Add Skills Modal ── */
    function renderModalQueue(){
        var tbody = document.getElementById('skillStagedBody');
        var sec   = document.getElementById('skillStagedSection');
        var ctr   = document.getElementById('modalSkillCount');
        tbody.innerHTML = '';
        if(modalQueue.length === 0){ sec.style.display='none'; ctr.textContent=''; return; }
        sec.style.display='block';
        ctr.textContent = modalQueue.length + ' skill(s) ready to save';
        modalQueue.forEach(function(item, idx){
            var tr = document.createElement('tr');
            tr.innerHTML = '<td style="font-size:12px;">'+esc(item.typeName)+'</td>'+
                '<td style="font-size:12px;">'+esc(item.skillName)+'</td>'+
                '<td style="font-size:12px;"><span class="badge bg-primary">'+esc(item.levelName)+'</span></td>'+
                '<td><button type="button" class="btn btn-sm btn-link text-danger p-0" data-idx="'+idx+'"><i class="fa fa-times"></i></button></td>';
            tbody.appendChild(tr);
        });
        tbody.querySelectorAll('button[data-idx]').forEach(function(btn){
            btn.addEventListener('click', function(){
                modalQueue.splice(parseInt(this.dataset.idx),1); renderModalQueue();
            });
        });
    }

    document.getElementById('openSkillModal').addEventListener('click', function(){
        modalQueue = [];
        typeSelect.value = '';
        skillSelect.innerHTML='<option value="">— Select Skill —</option>'; skillSelect.disabled=true;
        levelSelect.innerHTML='<option value="">— Select Level —</option>'; levelSelect.disabled=true;
        renderModalQueue();
        openModal('addSkillModal');
    });
    document.getElementById('closeSkillModal').addEventListener('click',  function(){ closeModal('addSkillModal'); });
    document.getElementById('closeSkillModal2').addEventListener('click', function(){ closeModal('addSkillModal'); });
    document.getElementById('addSkillModal').addEventListener('click', function(e){ if(e.target===this) closeModal('addSkillModal'); });

    document.getElementById('addSkillToList').addEventListener('click', function(){
        var typeOpt  = typeSelect.options[typeSelect.selectedIndex];
        var skillOpt = skillSelect.options[skillSelect.selectedIndex];
        var levelOpt = levelSelect.options[levelSelect.selectedIndex];
        if(!typeSelect.value)  { showMsg('Please select a Skill Type.','error'); return; }
        if(!skillSelect.value) { showMsg('Please select a Skill.','error'); return; }
        if(!levelSelect.value) { showMsg('Please select a Level.','error'); return; }
        if(modalQueue.some(function(i){ return i.skillId===skillSelect.value; })){ showMsg('This skill is already in the list.','error'); return; }
        modalQueue.push({
            typeId:typeSelect.value, typeName:typeOpt?typeOpt.textContent:'',
            skillId:skillSelect.value, skillName:skillOpt?skillOpt.textContent:'',
            levelId:levelSelect.value, levelName:levelOpt?levelOpt.textContent:'',
        });
        renderModalQueue();
        skillSelect.value=''; levelSelect.value='';
    });

    document.getElementById('saveSkillModal').addEventListener('click', function(){
        if(modalQueue.length === 0){ showMsg('Please add at least one skill.','error'); return; }
        var emptyRow = document.getElementById('skillEmptyRow');
        if(emptyRow) emptyRow.remove();
        var batchItems = modalQueue.map(function(item){
            return { skill_id:item.skillId, skill_name:item.skillName, level_id:item.levelId, level_name:item.levelName, type_id:item.typeId, type_name:item.typeName };
        });
        pendingChanges.push({ type:'add_batch', rowId:null, payload:{ batch_skills:batchItems } });
        var tbody = document.getElementById('skillTableBody');
        modalQueue.forEach(function(item){
            var rowTempId = tempId--;
            var tr = document.createElement('tr');
            tr.setAttribute('data-id',rowTempId); tr.setAttribute('data-skill-name',item.skillName);
            tr.setAttribute('data-type-name',item.typeName); tr.setAttribute('data-type-id',item.typeId);
            tr.setAttribute('data-level-name',item.levelName); tr.setAttribute('data-level-id',item.levelId);
            tr.classList.add('skill-staged-add');
            tr.innerHTML =
                '<td style="padding:13px 18px;vertical-align:middle;font-size:14px;" class="col-type-name">'+esc(item.typeName)+'</td>'+
                '<td style="padding:13px 18px;vertical-align:middle;font-size:14px;" class="col-skill-name">'+esc(item.skillName)+'<span class="skill-badge badge-new">New</span></td>'+
                '<td style="padding:13px 18px;vertical-align:middle;font-size:14px;" class="col-level-name"><span class="badge bg-primary">'+esc(item.levelName)+'</span></td>'+
                '<td class="skill-action-col" style="padding:13px 18px;vertical-align:middle;text-align:right;white-space:nowrap;">'+
                    '<button type="button" class="btn btn-sm btn-outline-danger ess-btn-delete-skill" data-id="'+rowTempId+'"><i class="fa fa-trash"></i></button>'+
                '</td>';
            tbody.appendChild(tr);
            bindDelete(tr);
        });
        updateBadge();
        saveToStorage();
        closeModal('addSkillModal');
        showMsg(modalQueue.length+' skill(s) staged. Accept the disclaimer and click "Submit for HR Approval".','info');
        modalQueue = [];
    });

    /* ── Edit Skill Modal ── */
    function bindEdit(){
        document.querySelectorAll('.ess-btn-edit-skill').forEach(function(btn){
            btn.addEventListener('click', function(){
                var rowId = this.dataset.id;
                var row   = getRow(rowId); if(!row) return;
                document.getElementById('editRecordId').value  = rowId;
                document.getElementById('editTypeId').value    = row.dataset.typeId||'';
                document.getElementById('editTypeName').value  = row.dataset.typeName||'';
                document.getElementById('editSkillName').value = row.dataset.skillName||'';
                var lsel = document.getElementById('editLevelSelect');
                lsel.innerHTML = '<option value="">— Select Level —</option>';
                (skillData.levels[row.dataset.typeId]||[]).forEach(function(lv){
                    var opt=document.createElement('option'); opt.value=lv.id; opt.textContent=lv.name; lsel.appendChild(opt);
                });
                lsel.value = row.dataset.levelId||'';
                openModal('editSkillModal');
            });
        });
    }
    bindEdit();
    document.getElementById('closeEditModal').addEventListener('click',  function(){ closeModal('editSkillModal'); });
    document.getElementById('closeEditModal2').addEventListener('click', function(){ closeModal('editSkillModal'); });
    document.getElementById('editSkillModal').addEventListener('click', function(e){ if(e.target===this) closeModal('editSkillModal'); });

    document.getElementById('saveEditBtn').addEventListener('click', function(){
        var rowId     = document.getElementById('editRecordId').value;
        var lsel      = document.getElementById('editLevelSelect');
        var levelId   = lsel.value;
        var levelName = lsel.options[lsel.selectedIndex] ? lsel.options[lsel.selectedIndex].textContent : '';
        if(!levelId){ showMsg('Please select a level.','error'); return; }
        pendingChanges = pendingChanges.filter(function(c){ return !(c.rowId==rowId&&c.type==='edit'); });
        pendingChanges.push({type:'edit', rowId:rowId, payload:{level_id:levelId, level_name:levelName}});
        var row = getRow(rowId);
        if(row){
            row.setAttribute('data-level-id',levelId); row.setAttribute('data-level-name',levelName);
            row.querySelector('.col-level-name').innerHTML='<span class="badge bg-primary">'+esc(levelName)+'</span>';
            if(!row.classList.contains('skill-staged-add')){ row.classList.add('skill-staged-edit'); setBadge(row,'edit'); }
        }
        updateBadge(); closeModal('editSkillModal'); showMsg('Edit staged.','info');
    });

    /* ── Delete staging ── */
    function bindDelete(row){
        var btn = row.querySelector('.ess-btn-delete-skill'); if(!btn) return;
        btn.addEventListener('click', function(){
            var rowId  = this.dataset.id;
            var isTemp = parseInt(rowId,10) < 0;
            if(!confirm('Remove this skill?')) return;
            if(isTemp){
                pendingChanges = pendingChanges.filter(function(c){ return c.type !== 'add_batch'; });
                var r = getRow(rowId); if(r) r.remove();
            } else {
                pendingChanges = pendingChanges.filter(function(c){ return !(c.rowId==rowId&&(c.type==='edit'||c.type==='delete')); });
                pendingChanges.push({type:'delete', rowId:rowId, payload:{}});
                var r = getRow(rowId);
                if(r){
                    r.classList.remove('skill-staged-edit'); r.classList.add('skill-staged-delete');
                    setBadge(r,'delete');
                    r.querySelector('.skill-action-col').innerHTML =
                        '<button type="button" class="btn btn-sm btn-outline-secondary ess-btn-undo" data-id="'+rowId+'" title="Undo"><i class="fa fa-undo me-1"></i>Undo</button>';
                    bindUndo(r);
                }
            }
            updateBadge();
        });
    }

    function bindUndo(row){
        var btn = row.querySelector('.ess-btn-undo'); if(!btn) return;
        btn.addEventListener('click', function(){
            var rowId = this.dataset.id;
            pendingChanges = pendingChanges.filter(function(c){ return !(c.rowId==rowId&&c.type==='delete'); });
            row.classList.remove('skill-staged-delete'); clearBadge(row);
            row.querySelector('.skill-action-col').innerHTML =
                '<button type="button" class="btn btn-sm btn-outline-warning ess-btn-edit-skill me-1" data-id="'+rowId+'" title="Edit"><i class="fa fa-pencil"></i></button>'+
                '<button type="button" class="btn btn-sm btn-outline-danger ess-btn-delete-skill" data-id="'+rowId+'" title="Delete"><i class="fa fa-trash"></i></button>';
            bindEdit(); bindDelete(row); updateBadge(); showMsg('Undo successful.','info');
        });
    }

    document.querySelectorAll('#skillTableBody tr[data-id]').forEach(function(row){ bindDelete(row); });

    /* ── Edit mode toggle ── */
    function enableEdit(){
        document.getElementById('openSkillModal').style.display='inline-flex';
        document.getElementById('skillActionHeader').style.display='';
        document.querySelectorAll('.skill-action-col').forEach(function(td){ td.style.display=''; });
        var h=document.getElementById('skillEmptyHint'); if(h) h.style.display='';
        var rs=document.getElementById('resumeEditSection'); if(rs) rs.style.display='block';
        document.getElementById('expViewActions').style.display='none';
        document.getElementById('expFormActions').style.display='block';
        var disc=document.getElementById('expDisclaimer'); if(disc) disc.checked=false;
        var btn=document.getElementById('expSaveBtn'); if(btn){ btn.disabled=true; btn.style.opacity='0.6'; }
        updateBadge();
    }

    function disableEdit(){
        document.getElementById('openSkillModal').style.display='none';
        document.getElementById('skillActionHeader').style.display='none';
        document.querySelectorAll('.skill-action-col').forEach(function(td){ td.style.display='none'; });
        var h=document.getElementById('skillEmptyHint'); if(h) h.style.display='none';
        var rs=document.getElementById('resumeEditSection'); if(rs) rs.style.display='none';
        var rfi=document.getElementById('resumeFileInput'); if(rfi) rfi.value='';
        var rfl=document.getElementById('resumeFileLabel'); if(rfl) rfl.style.display='none';
        document.getElementById('expViewActions').style.display='block';
        document.getElementById('expFormActions').style.display='none';
        var disc=document.getElementById('expDisclaimer'); if(disc) disc.checked=false;
        var btn=document.getElementById('expSaveBtn'); if(btn){ btn.disabled=true; btn.style.opacity='0.6'; }
    }

    document.getElementById('expEditBtn').addEventListener('click', function(){
        if(this.disabled) return;
        enableEdit();
    });

    document.getElementById('expCancelBtn').addEventListener('click', function(){
        if(pendingChanges.length>0 && !confirm('Discard all unsaved changes?')) return;
        pendingChanges=[];
        isSubmitting=true;
        disableEdit();
        location.reload();
    });

    /* ── FIX 3: Submit — immediately lock edit mode, single submission only ── */
    document.getElementById('expSaveBtn').addEventListener('click', function(){
        var disc = document.getElementById('expDisclaimer');
        if(disc && !disc.checked){
            showMsg('Please read and accept the Employee Disclaimer before submitting.','error');
            return;
        }
        if(pendingChanges.length === 0){ disableEdit(); return; }

        var btn = this;

        /* Immediately lock everything — no second click possible during submit */
        btn.disabled = true;
        btn.innerHTML = '<i class="fa fa-spinner fa-spin me-1"></i>Submitting...';
        document.getElementById('expCancelBtn').disabled = true;
        document.getElementById('expDisclaimer').disabled = true;
        document.getElementById('openSkillModal').style.display = 'none';
        document.querySelectorAll('.skill-action-col').forEach(function(td){ td.style.display='none'; });

        /* Merge all add_batch entries into one single batch — ONE PCR for all skills */
        var mergedSkills = [];
        var otherChanges = [];
        pendingChanges.forEach(function(c) {
            if (c.type === 'add_batch' && c.payload && c.payload.batch_skills) {
                mergedSkills = mergedSkills.concat(c.payload.batch_skills);
            } else {
                otherChanges.push(c);
            }
        });
        if (mergedSkills.length > 0) {
            otherChanges.unshift({ type:'add_batch', rowId:null, payload:{ batch_skills: mergedSkills } });
        }
        var changes = otherChanges;
        var errors  = [];

        /* ── COMBINED SUBMIT: skill + resume in ONE PCR if both present ── */
        var hasResume = changes.some(function(c){ return c.type === 'resume'; });
        var hasSkills = changes.some(function(c){ return c.type === 'add_batch' || c.type === 'edit' || c.type === 'delete'; });

        if(hasResume && hasSkills){
            /* ONE PCR for both skill + resume — same sequence number */
            var rfi = document.getElementById('resumeFileInput');
            if(!rfi || !rfi.files || rfi.files.length === 0){
                showMsg('Resume file not found. Please re-attach the file.', 'error');
                btn.disabled = false;
                btn.innerHTML = '<i class="fa fa-paper-plane me-1"></i>Submit for HR Approval';
                document.getElementById('expCancelBtn').disabled = false;
                document.getElementById('expDisclaimer').disabled = false;
                return;
            }

            /* Merge all batch skills into one */
            var mergedSkills = [];
            changes.forEach(function(c){
                if(c.type === 'add_batch' && c.payload && c.payload.batch_skills){
                    mergedSkills = mergedSkills.concat(c.payload.batch_skills);
                }
            });

            var combinedFd = new FormData();
            combinedFd.append('csrf_token', csrfToken);
            combinedFd.append('action', 'submit_combined');
            if(mergedSkills.length > 0){
                combinedFd.append('batch_skills', JSON.stringify(mergedSkills));
            }
            combinedFd.append('resume_file', rfi.files[0], rfi.files[0].name);

            fetch(BASE_URL, {method:'POST', body:combinedFd})
                .then(function(r){ return r.json(); })
                .then(function(d){
                    if(!d.success){
                        showMsg('Failed: '+(d.error||'unknown error'), 'error');
                        btn.disabled = false;
                        btn.innerHTML = '<i class="fa fa-paper-plane me-1"></i>Submit for HR Approval';
                        document.getElementById('expCancelBtn').disabled = false;
                        document.getElementById('expDisclaimer').disabled = false;
                    } else {
                        showSuccessOverlay();
                    }
                })
                .catch(function(){
                    showMsg('Network error. Please try again.', 'error');
                    btn.disabled = false;
                    btn.innerHTML = '<i class="fa fa-paper-plane me-1"></i>Submit for HR Approval';
                    document.getElementById('expCancelBtn').disabled = false;
                    document.getElementById('expDisclaimer').disabled = false;
                });
            return;
        }

        function showSuccessOverlay(){
            showMsg('Changes submitted! Reloading...', 'success');
            pendingChanges = [];
            isSubmitting = true;
            try { localStorage.removeItem(EXP_KEY); } catch(ex) {}
            var addBtn = document.getElementById('openSkillModal');
            if (addBtn) { addBtn.disabled = true; addBtn.style.opacity = '0.5'; }
            var overlay = document.createElement('div');
            overlay.style.cssText = 'position:fixed;inset:0;z-index:99999;background:rgba(255,255,255,0.95);display:flex;align-items:center;justify-content:center;';
            overlay.innerHTML = '<div style="text-align:center;padding:32px;background:white;border-radius:16px;box-shadow:0 8px 40px rgba(0,0,0,0.12);max-width:420px;">' +
                '<div style="font-size:52px;margin-bottom:14px;">✅</div>' +
                '<h4 style="color:#155724;font-weight:700;margin-bottom:10px;">Submitted!</h4>' +
                '<p style="color:#555;margin-bottom:12px;">Your changes have been sent to HR for approval.</p>' +
                '<p style="color:#888;font-size:13px;"><i class="fa fa-refresh fa-spin me-1"></i>Reloading...</p>' +
                '<div style="height:4px;background:#e0e0e0;border-radius:4px;overflow:hidden;width:180px;margin:12px auto 0;">' +
                '<div id="exp-prog" style="height:100%;width:0%;background:#0d6efd;border-radius:4px;transition:width 1.3s linear;"></div></div>' +
                '</div>';
            document.body.appendChild(overlay);
            setTimeout(function(){ var p=document.getElementById('exp-prog'); if(p) p.style.width='100%'; }, 50);
            setTimeout(function(){ location.reload(); }, 1500);
        }

        function next(i){
            if(i >= changes.length){
                if(errors.length > 0){
                    showMsg('Some changes failed: ' + errors.join('; '), 'error');
                    btn.disabled = false;
                    btn.innerHTML = '<i class="fa fa-paper-plane me-1"></i>Submit for HR Approval';
                    document.getElementById('expCancelBtn').disabled = false;
                    document.getElementById('expDisclaimer').disabled = false;
                } else {
                    showSuccessOverlay();
                }
                return;
            }

            var c  = changes[i];
            var fd = new FormData();
            fd.append('csrf_token', csrfToken);

            if(c.type === 'add_batch'){
                fd.append('action', 'add_skill');
                fd.append('batch_skills', JSON.stringify(c.payload.batch_skills));
                fetch(BASE_URL, {method:'POST', body:fd})
                    .then(function(r){ return r.json(); })
                    .then(function(d){ if(!d.success) errors.push('batch add: '+(d.error||'failed')); next(i+1); })
                    .catch(function(){ errors.push('batch add: network error'); next(i+1); });

            } else if(c.type === 'edit'){
                fd.append('action', 'edit_skill');
                fd.append('skill_record_id', c.rowId);
                fd.append('level_id',   c.payload.level_id);
                fd.append('level_name', c.payload.level_name);
                fetch(BASE_URL, {method:'POST', body:fd})
                    .then(function(r){ return r.json(); })
                    .then(function(d){ if(!d.success) errors.push('edit: '+(d.error||'failed')); next(i+1); })
                    .catch(function(){ errors.push('edit: network error'); next(i+1); });

            } else if(c.type === 'delete'){
                fd.append('action', 'delete_skill');
                fd.append('skill_record_id', c.rowId);
                fetch(BASE_URL, {method:'POST', body:fd})
                    .then(function(r){ return r.json(); })
                    .then(function(d){ if(!d.success) errors.push('delete: '+(d.error||'failed')); next(i+1); })
                    .catch(function(){ errors.push('delete: network error'); next(i+1); });

            } else if(c.type === 'resume'){
                var rfi = document.getElementById('resumeFileInput');
                if(!rfi || !rfi.files || rfi.files.length === 0){
                    errors.push('Resume: file not found'); next(i+1); return;
                }
                var resumeFd = new FormData();
                resumeFd.append('csrf_token', csrfToken);
                resumeFd.append('action', 'upload_resume');
                resumeFd.append('resume_file', rfi.files[0], rfi.files[0].name);
                fetch(BASE_URL, {method:'POST', body:resumeFd})
                    .then(function(r){ return r.json(); })
                    .then(function(d){ if(!d.success) errors.push('Resume: '+(d.error||'failed')); next(i+1); })
                    .catch(function(){ errors.push('Resume: network error'); next(i+1); });

            } else {
                next(i+1);
            }
        }

        next(0);
    });

}); /* end DOMContentLoaded */
})();
//
